  'A complete intake before your first visit — contact details, insurance, history, and consents.',
  '{"blocks":[{"id":"s_welcome","type":"info","label":"Welcome to Liminal. This intake helps your care team get to know you before your first visit — it takes about ten minutes and your answers are confidential.","required":false},{"id":"full_name","type":"text","label":"Full legal name","required":true},{"id":"preferred_name","type":"text","label":"Preferred name","required":false},{"id":"dob","type":"date","label":"Date of birth","required":true},{"id":"pronouns","type":"text","label":"Pronouns","required":false},{"id":"gender","type":"select","label":"Gender","options":["Female","Male","Non-binary","Prefer to self-describe","Prefer not to say"],"required":false},{"id":"phone","type":"text","label":"Mobile phone","required":true},{"id":"email","type":"text","label":"Email address","required":true},{"id":"address","type":"textarea","label":"Home address","required":false},{"id":"s_emergency","type":"info","label":"Emergency contact — someone we can reach if there''s an urgent concern.","required":false},{"id":"ec_name","type":"text","label":"Emergency contact name","required":true},{"id":"ec_relationship","type":"text","label":"Relationship to you","required":true},{"id":"ec_phone","type":"text","label":"Emergency contact phone","required":true},{"id":"s_insurance","type":"info","label":"Insurance — so we can verify your benefits. Skip this if you''re paying out of pocket.","required":false},{"id":"ins_carrier","type":"text","label":"Insurance carrier","required":false},{"id":"ins_member_id","type":"text","label":"Member ID","required":false},{"id":"ins_group","type":"text","label":"Group number","required":false},{"id":"ins_subscriber","type":"text","label":"Policyholder name (if not you)","required":false},{"id":"s_concerns","type":"info","label":"What brings you in — in your own words. There are no wrong answers.","required":false},{"id":"reason","type":"textarea","label":"What would you like help with?","required":true},{"id":"goals","type":"textarea","label":"What would a good outcome look like for you?","required":false},{"id":"duration","type":"select","label":"How long has this been going on?","options":["Less than a month","1–6 months","6–12 months","More than a year","As long as I can remember"],"required":false},{"id":"s_history","type":"info","label":"History — a brief picture of your health so far.","required":false},{"id":"prior_care","type":"textarea","label":"Previous mental-health care (providers, therapy, diagnoses)","required":false},{"id":"hospitalizations","type":"yesno","label":"Have you ever been hospitalized for a mental-health reason?","required":false},{"id":"medical_conditions","type":"textarea","label":"Ongoing medical conditions","required":false},{"id":"family_history","type":"textarea","label":"Family history of mental-health or substance-use conditions","required":false},{"id":"safety","type":"radio","label":"In the past month, have you had thoughts of harming yourself?","options":["No","Yes","Prefer to discuss in session"],"required":true},{"id":"s_meds","type":"info","label":"Medications & allergies — include anything over-the-counter or herbal.","required":false},{"id":"medications","type":"textarea","label":"Current medications and doses","required":false},{"id":"allergies","type":"text","label":"Medication allergies","required":false},{"id":"substances","type":"textarea","label":"Alcohol, nicotine, cannabis, or other substance use","required":false},{"id":"s_consent","type":"info","label":"Consents — please review and acknowledge before your first visit.","required":false},{"id":"consent_treat","type":"checkbox","label":"I consent to evaluation and treatment.","required":true},{"id":"consent_privacy","type":"checkbox","label":"I have reviewed the Notice of Privacy Practices.","required":true},{"id":"consent_telehealth","type":"checkbox","label":"I consent to telehealth visits where appropriate.","required":false},{"id":"consent_financial","type":"checkbox","label":"I understand the financial and cancellation policy.","required":true},{"id":"signature","type":"signature","label":"Signature","required":true}]}'::jsonb,
